import csv, json
from datetime import datetime

with open('/app/sales_data.csv', 'r') as f:
    reader = csv.DictReader(f)
    valid = 0
    for row in reader:
        if not row['customer_id'].strip():
            continue
        try:
            amt = float(row['amount'])
        except ValueError:
            continue
        if amt <= 0:
            continue
        try:
            datetime.strptime(row['transaction_date'].strip(), '%m/%d/%Y')
        except ValueError:
            continue
        valid += 1
    print(f'Valid rows in CSV: {valid}')

with open('/app/sales_summary.json', 'r') as f:
    data = json.load(f)
    total_trans = sum(item['transaction_count'] for item in data)
    print(f'Total transactions in summary: {total_trans}')
    if valid == total_trans:
        print('Counts match!')
    else:
        print('Mismatch!')
EOF

